impl From<Duration> for KeepAlive {
    fn from(dur: Duration) -> Self {
        KeepAlive::Timeout(dur).normalize()
    }
}

impl From<Option<Duration>> for KeepAlive {
    fn from(ka_dur: Option<Duration>) -> Self {
        match ka_dur {
            Some(dur) => KeepAlive::from(dur),
            None => KeepAlive::Disabled,
        }
        .normalize()
    }
}

#[async_trait]
impl Filter for SchemeFilter {
    #[inline]
    async fn filter(&self, req: &mut Request, _state: &mut PathState) -> bool {
        req.uri()
            .scheme()
            .map(|s| s == &self.scheme)
            .unwrap_or(self.fallback)
    }
    #[inline]
    fn info(&self) -> FilterInfo {
        FilterInfo::Scheme(self.scheme.clone())
    }
}

struct DefaultStatusOK;
#[async_trait]
impl Handler for DefaultStatusOK {
    async fn handle(
        &self,
        req: &mut Request,
        depot: &mut Depot,
        res: &mut Response,
        ctrl: &mut FlowCtrl,
    ) {
        ctrl.call_next(req, depot, res).await;
        if res.status_code.is_none() {
            res.status_code = Some(StatusCode::OK);
        }
    }
}

#[async_trait]
impl<P> Writer for Option<P>
where
    P: Scribe + Sized + Send,
{
    #[inline]
    async fn write(self, _req: &mut Request, _depot: &mut Depot, res: &mut Response) {
        match self {
            Some(v) => v.render(res),
            None => {
                res.status_code(StatusCode::NOT_FOUND);
            }
        }
    }
}

#[must_use]
    pub fn very_permissive() -> Self {
        tracing::warn!(
            "Using Cors::very_permissive() - this disables CORS security and should not be used in production!"
        );
        Self::new()
            .allow_credentials(true)
            .allow_headers(AllowHeaders::mirror_request())
            .allow_methods(AllowMethods::mirror_request())
            .allow_origin(AllowOrigin::mirror_request())
    }

fn take_route_or_internal_error(service: &mut Option<Route>) -> Route {
    service.take().unwrap_or_else(|| {
        if cfg!(debug_assertions) {
            panic!("{TAKE_ONCE_ROUTE_PANIC_MSG}");
        }

        Route::new(service_fn(|_req: Request| async move {
            Ok::<_, Infallible>(http::StatusCode::INTERNAL_SERVER_ERROR.into_response())
        }))
    })
}

match (req.method(), req.uri().path()) {
    (&Method::GET, "/") | (&Method::GET, "/index.html") => Ok(Response::new(full(INDEX))),
    (&Method::GET, "/test.html") => client_request_response().await,
    (&Method::POST, "/json_api") => api_post_response(req).await,
    (&Method::GET, "/json_api") => api_get_response().await,
